import { runWithBackoff } from "@1771technologies/js-utils";
import { queryCell, queryFullWidthRow } from "./query.js";
export function focusCell({ focusActive, id, vp, rowIndex, colIndex, getRootCell, scrollIntoView, postFocus, }) {
    scrollIntoView({ row: rowIndex, column: colIndex, behavior: "instant" });
    if (!vp)
        return false;
    const run = () => {
        const root = getRootCell(rowIndex, colIndex);
        if (!root)
            return false;
        if (root.kind === "full-width") {
            const el = queryFullWidthRow(id, root.rowIndex, vp);
            if (!el)
                return false;
            el.focus();
            if (postFocus)
                queueMicrotask(postFocus);
            focusActive.set((prev) => ({ ...prev, colIndex }));
            return true;
        }
        const el = queryCell(id, rowIndex, colIndex, vp);
        if (!el)
            return false;
        el.focus();
        if (postFocus)
            queueMicrotask(postFocus);
        return true;
    };
    runWithBackoff(run, [8, 20]);
    return true;
}
